package tests;import base.BaseTest;import pages.CocineroPage;import pages.CrearPlatoPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP06AgregarPlatoTest extends BaseTest {    @Test    void cocineroAgregaNuevoPlato() {        try {            System.out.println(                    "Ejecutando HP-06: Crear nuevo plato"            );            LoginPage loginPage =                    new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion(                    "cocinero",                    "123"            );            Thread.sleep(3000);            CocineroPage cocineroPage =                    new CocineroPage(driver);            cocineroPage.irACrearPlato();            Thread.sleep(2000);            CrearPlatoPage crearPlatoPage =                    new CrearPlatoPage(driver);            String nombre =                    "Plato QA " + System.currentTimeMillis();            crearPlatoPage.ingresarNombre(nombre);            crearPlatoPage.ingresarDescripcion(                    "Creado por Selenium"            );            crearPlatoPage.ingresarPrecio("25");            crearPlatoPage.crearPlato();            Thread.sleep(3000);            Assertions.assertTrue(                    cocineroPage.panelVisible(),                    "Después de crear el plato no se redirigió al Panel Cocinero."            );            Assertions.assertTrue(                    driver.getPageSource().contains("Añadir Plato"),                    "No se visualiza el botón Añadir Plato después de crear el plato."            );            System.out.println("HP-06 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail(                    "Error en HP-06: "                            + e.getMessage()            );        }    }}